/**
 * flow-description-sync.js
 *
 * Updates the top-level <description> element in flow XML files based on
 * existing repo documentation. Keeps XML descriptions in sync with docs
 * during commits.
 *
 * Usage:
 *   node scripts/flow-description-sync.js <FlowName1> <FlowName2> ...
 *   node scripts/flow-description-sync.js --from-files path1.xml path2.xml ...
 *   node scripts/flow-description-sync.js --dry-run <FlowName1> ...
 *   node scripts/flow-description-sync.js --metadata-path src/main/default --docs-path docs/flows <FlowName1> ...
 *
 * Options:
 *   --metadata-path <path>   Path to SFDX metadata directory (default: force-app/main/default)
 *   --docs-path <path>       Path to flow documentation directory (default: docs/flows)
 *   --github-base <url>      Base GitHub URL for doc links (default: none — omits doc link)
 *   --dry-run                Show what would change without modifying files
 *   --from-files             Accept full file paths instead of flow API names
 *   --json                   Output results as JSON
 *   --help                   Show this help message
 *
 * Exit codes:
 *   0 — All flows processed successfully
 *   1 — Some flows skipped (no doc found) but others succeeded
 *   2 — Error (bad args, no flows provided)
 */

const fs = require("fs");
const path = require("path");

const REPO_ROOT = path.join(__dirname, "..");

// --- CLI argument parsing ---

const args = process.argv.slice(2);

if (args.includes("--help")) {
  const lines = [];
  lines.push("flow-description-sync.js — Sync flow XML <description> from repo docs");
  lines.push("");
  lines.push("Usage:");
  lines.push("  node scripts/flow-description-sync.js [options] <FlowName1> <FlowName2> ...");
  lines.push("  node scripts/flow-description-sync.js [options] --from-files path1.xml path2.xml ...");
  lines.push("");
  lines.push("Options:");
  lines.push("  --metadata-path <path>   Path to SFDX metadata directory (default: force-app/main/default)");
  lines.push("  --docs-path <path>       Path to flow documentation directory (default: docs/flows)");
  lines.push("  --github-base <url>      Base GitHub URL for doc links (omitted if not set)");
  lines.push("  --dry-run                Show what would change without modifying files");
  lines.push("  --from-files             Accept full file paths instead of flow API names");
  lines.push("  --json                   Output results as JSON");
  lines.push("  --help                   Show this help message");
  lines.push("");
  lines.push("Exit codes:");
  lines.push("  0 — All flows processed successfully");
  lines.push("  1 — Some flows skipped (no doc found) but others succeeded");
  lines.push("  2 — Error (bad args, no flows provided)");
  console.log(lines.join("\n"));
  process.exit(0);
}

const dryRun = args.includes("--dry-run");
const fromFiles = args.includes("--from-files");
const jsonOutput = args.includes("--json");

const metadataPath = getArgValue(args, "--metadata-path") || "force-app/main/default";
const docsPath = getArgValue(args, "--docs-path") || "docs/flows";
const githubBase = getArgValue(args, "--github-base") || null;

const FLOWS_DIR = path.join(REPO_ROOT, metadataPath, "flows");
const DOCS_DIR = path.join(REPO_ROOT, docsPath);

const flowArgs = args.filter(
  (a) =>
    !a.startsWith("--") &&
    a !== getArgValue(args, "--metadata-path") &&
    a !== getArgValue(args, "--docs-path") &&
    a !== getArgValue(args, "--github-base")
);

// Remove values that follow --flags from flowArgs
const cleanFlowArgs = [];
for (let i = 0; i < args.length; i++) {
  const a = args[i];
  if (a === "--metadata-path" || a === "--docs-path" || a === "--github-base") {
    i++; // skip the value
    continue;
  }
  if (a.startsWith("--")) continue;
  cleanFlowArgs.push(a);
}

if (cleanFlowArgs.length === 0) {
  console.error(
    "Usage: node scripts/flow-description-sync.js [--dry-run] [--from-files] <FlowName|path> ..."
  );
  process.exit(2);
}

// --- Main ---

const results = [];
let hasSkips = false;

for (const arg of cleanFlowArgs) {
  let flowName, xmlPath;

  if (fromFiles) {
    xmlPath = path.resolve(arg);
    flowName = path.basename(arg, ".flow-meta.xml");
  } else {
    flowName = arg;
    xmlPath = path.join(FLOWS_DIR, `${flowName}.flow-meta.xml`);
  }

  if (!fs.existsSync(xmlPath)) {
    results.push({
      flow: flowName,
      status: "skipped",
      reason: "XML not found"
    });
    hasSkips = true;
    continue;
  }

  const category = getCategory(flowName);
  if (!category) {
    results.push({
      flow: flowName,
      status: "skipped",
      reason: "No category/doc found"
    });
    hasSkips = true;
    continue;
  }

  const docPath = path.join(DOCS_DIR, category, `${flowName}.md`);
  if (!fs.existsSync(docPath)) {
    results.push({
      flow: flowName,
      status: "skipped",
      reason: `No doc at ${docsPath}/${category}/${flowName}.md`
    });
    hasSkips = true;
    continue;
  }

  const purpose = extractPurpose(docPath);
  if (!purpose) {
    results.push({
      flow: flowName,
      status: "skipped",
      reason: "Could not extract purpose from doc"
    });
    hasSkips = true;
    continue;
  }

  const description = buildDescription(purpose, category, flowName);
  const result = updateFlowXml(xmlPath, description, dryRun);

  results.push({
    flow: flowName,
    category,
    status: result.updated
      ? result.changed
        ? "updated"
        : "unchanged"
      : "error",
    description: description,
    error: result.error || undefined
  });
}

// Output
if (jsonOutput) {
  console.log(JSON.stringify(results, null, 2));
} else {
  const prefix = dryRun ? "[dry-run] " : "";
  for (const r of results) {
    if (r.status === "updated") {
      console.log(`${prefix}Updated: ${r.flow} (${r.category})`);
    } else if (r.status === "unchanged") {
      console.log(`${prefix}Unchanged: ${r.flow} (${r.category})`);
    } else if (r.status === "skipped") {
      console.log(`${prefix}Skipped: ${r.flow} — ${r.reason}`);
    } else {
      console.log(`${prefix}Error: ${r.flow} — ${r.error}`);
    }
  }

  const updated = results.filter((r) => r.status === "updated").length;
  const unchanged = results.filter((r) => r.status === "unchanged").length;
  const skipped = results.filter((r) => r.status === "skipped").length;
  console.log(
    `\n${prefix}Summary: ${updated} updated, ${unchanged} unchanged, ${skipped} skipped`
  );
}

process.exit(
  hasSkips && results.every((r) => r.status === "skipped")
    ? 2
    : hasSkips
      ? 1
      : 0
);

// ============================================================
// Functions
// ============================================================

/**
 * Get the value following a named argument (e.g. --metadata-path src/main).
 */
function getArgValue(args, name) {
  const idx = args.indexOf(name);
  if (idx === -1 || idx + 1 >= args.length) return null;
  return args[idx + 1];
}

/**
 * Determine the category for a flow name.
 * Scans docs directory subdirectories to find which category contains a doc for this flow.
 */
function getCategory(flowName) {
  if (!fs.existsSync(DOCS_DIR)) return null;

  const categories = fs.readdirSync(DOCS_DIR).filter((d) => {
    const full = path.join(DOCS_DIR, d);
    return fs.statSync(full).isDirectory() && !d.startsWith(".");
  });

  for (const cat of categories) {
    const docPath = path.join(DOCS_DIR, cat, `${flowName}.md`);
    if (fs.existsSync(docPath)) return cat;
  }

  return null;
}

/**
 * Extract the Purpose/What It Does text from a flow's markdown doc.
 * Returns a single sentence suitable for the XML description.
 */
function extractPurpose(docPath) {
  // Normalize line endings to LF for consistent regex matching
  const content = fs.readFileSync(docPath, "utf8").replace(/\r\n/g, "\n");

  // Look for ## Purpose or ## What It Does section
  const purposeMatch = content.match(
    /^##\s+(?:Purpose|What It Does)\s*\n\n([\s\S]*?)(?=\n##\s|\n$)/m
  );
  if (!purposeMatch) return null;

  const purposeText = purposeMatch[1].trim();

  // Take the first sentence (up to first period followed by space or end)
  const firstSentence = purposeText.match(/^[^.]+\./);
  if (firstSentence) {
    return firstSentence[0].trim();
  }

  // If no period found, take first 100 chars
  return purposeText.substring(0, 100).trim();
}

/**
 * Build the description string for a flow's XML.
 * Format: "{purpose}" or "{purpose} Docs: {github url}" if --github-base is set.
 * Max 255 characters.
 */
function buildDescription(purpose, category, flowName) {
  if (!githubBase) {
    // No GitHub base URL — just use the purpose text
    return purpose.length <= 255 ? purpose : purpose.substring(0, 252) + "...";
  }

  const docsUrl = `${githubBase}/${category}/${flowName}.md`;
  let desc = `${purpose} Docs: ${docsUrl}`;

  if (desc.length <= 255) return desc;

  // Truncate purpose to fit
  const maxPurpose = 255 - ` Docs: ${docsUrl}`.length;
  if (maxPurpose > 20) {
    desc = `${purpose.substring(0, maxPurpose - 3)}... Docs: ${docsUrl}`;
  } else {
    desc = desc.substring(0, 252) + "...";
  }

  return desc;
}

/**
 * Update the top-level <description> in a flow XML file.
 * Returns { updated: boolean, oldDesc: string|null, newDesc: string }
 */
function updateFlowXml(xmlPath, newDescription, dryRun) {
  const content = fs.readFileSync(xmlPath, "utf8");

  const topLevelDescRegex = /^(\s*)<description>([\s\S]*?)<\/description>\s*$/m;

  const flowElementTags = [
    "actionCalls",
    "assignments",
    "choices",
    "collectionProcessors",
    "constants",
    "decisions",
    "dynamicChoiceSets",
    "formulas",
    "loops",
    "processMetadataValues",
    "recordCreates",
    "recordDeletes",
    "recordLookups",
    "recordRollbacks",
    "recordUpdates",
    "screens",
    "start",
    "steps",
    "subflows",
    "variables",
    "waits"
  ];

  // Find the position of the first flow element
  let firstElementPos = content.length;
  for (const tag of flowElementTags) {
    const idx = content.indexOf(`<${tag}`);
    if (idx !== -1 && idx < firstElementPos) {
      firstElementPos = idx;
    }
  }

  const headerSection = content.substring(0, firstElementPos);
  const descMatch = headerSection.match(topLevelDescRegex);
  const escapedDesc = escapeXml(newDescription);

  let newContent;
  let oldDesc = null;

  if (descMatch) {
    oldDesc = descMatch[2];
    newContent = content.replace(
      descMatch[0],
      `${descMatch[1]}<description>${escapedDesc}</description>`
    );
  } else {
    // No top-level description — add after <apiVersion> or <areMetricsLoggedToDataCloud>
    const insertAfterTags = [
      "areMetricsLoggedToDataCloud",
      "apiVersion",
      "actionType"
    ];
    let inserted = false;

    for (const tag of insertAfterTags) {
      const tagRegex = new RegExp(`(\\s*<${tag}>[^<]*</${tag}>)`, "m");
      const tagMatch = headerSection.match(tagRegex);
      if (tagMatch) {
        const insertPoint = content.indexOf(tagMatch[0]) + tagMatch[0].length;
        const indent = tagMatch[0].match(/^(\s*)/)[1] || "    ";
        newContent =
          content.substring(0, insertPoint) +
          `\n${indent}<description>${escapedDesc}</description>` +
          content.substring(insertPoint);
        inserted = true;
        break;
      }
    }

    if (!inserted) {
      // Last resort: add after opening <Flow> tag
      const flowTagEnd = content.indexOf(">", content.indexOf("<Flow"));
      if (flowTagEnd !== -1) {
        newContent =
          content.substring(0, flowTagEnd + 1) +
          `\n    <description>${escapedDesc}</description>` +
          content.substring(flowTagEnd + 1);
      } else {
        return { updated: false, error: "Could not find insertion point" };
      }
    }
  }

  if (!dryRun && newContent) {
    fs.writeFileSync(xmlPath, newContent, "utf8");
  }

  return {
    updated: true,
    oldDesc: oldDesc,
    newDesc: newDescription,
    changed: oldDesc !== escapedDesc
  };
}

function escapeXml(str) {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}
